30:   // 1. Envoy starts up and if its can_healthcheck option in the static
31:   //    bootstrap config is enabled, sends HealthCheckRequest to the management
32:   //    server. It supplies its capabilities (which protocol it can health check
33:   //    with, what zone it resides in, etc.).
34:   // 2. In response to (1), the management server designates this Envoy as a
35:   //    healthchecker to health check a subset of all upstream hosts for a given
36:   //    cluster (for example upstream Host 1 and Host 2). It streams
37:   //    HealthCheckSpecifier messages with cluster related configuration for all
38:   //    clusters this Envoy is designated to health check. Subsequent
39:   //    HealthCheckSpecifier message will be sent on changes to:
40:   //    a. Endpoints to health checks
41:   //    b. Per cluster configuration change
42:   // 3. Envoy creates a health probe based on the HealthCheck config and sends
43:   //    it to endpoint(ip:port) of Host 1 and 2. Based on the HealthCheck
44:   //    configuration Envoy waits upon the arrival of the probe response and
45:   //    looks at the content of the response to decide whether the endpoint is
46:   //    healthy or not. If a response hasn't been received within the timeout
47:   //    interval, the endpoint health status is considered TIMEOUT.
48:   // 4. Envoy reports results back in an EndpointHealthResponse message.
49:   //    Envoy streams responses as often as the interval configured by the
50:   //    management server in HealthCheckSpecifier.
51:   // 5. The management Server collects health statuses for all endpoints in the
52:   //    cluster (for all clusters) and uses this information to construct
53:   //    EndpointDiscoveryResponse messages.
54:   // 6. Once Envoy has a list of upstream endpoints to send traffic to, it load
55:   //    balances traffic to them without additional health checking. It may
56:   //    use inline healthcheck (i.e. consider endpoint UNHEALTHY if connection
57:   //    failed to a particular endpoint to account for health status propagation
58:   //    delay between HDS and EDS).
59:   // By default, can_healthcheck is true. If can_healthcheck is false, Cluster
60:   // configuration may not contain HealthCheck message.
61:   // TODO(htuch): How is can_healthcheck communicated to CDS to ensure the above
62:   // invariant?
63:   // TODO(htuch): Add @amb67's diagram.
64:   rpc StreamHealthCheck(stream HealthCheckRequestOrEndpointHealthResponse)
65:       returns (stream HealthCheckSpecifier) {
66:   }
67: 
68:   // TODO(htuch): Unlike the gRPC version, there is no stream-based binding of
69:   // request/response. Should we add an identifier to the HealthCheckSpecifier
70:   // to bind with the response?
71:   rpc FetchHealthCheck(HealthCheckRequestOrEndpointHealthResponse) returns (HealthCheckSpecifier) {
72:     option (google.api.http).post = "/v2/discovery:health_check";
73:     option (google.api.http).body = "*";
74:   }
75: }
76: 
77: // Defines supported protocols etc, so the management server can assign proper
78: // endpoints to healthcheck.
79: message Capability {
80:   // Different Envoy instances may have different capabilities (e.g. Redis)
81:   // and/or have ports enabled for different protocols.
82:   enum Protocol {
83:     HTTP = 0;
84:     TCP = 1;
85:     REDIS = 2;
86:   }
87: 
88:   repeated Protocol health_check_protocols = 1;
89: }
90: 
91: message HealthCheckRequest {
92:   api.v2.core.Node node = 1;
93: 
94:   Capability capability = 2;
95: }
96: 
97: message EndpointHealth {
98:   api.v2.endpoint.Endpoint endpoint = 1;
99: 
100:   api.v2.core.HealthStatus health_status = 2;
101: }
102: 
103: message EndpointHealthResponse {
104:   repeated EndpointHealth endpoints_health = 1;
105: }
106: 
107: message HealthCheckRequestOrEndpointHealthResponse {
108:   oneof request_type {
109:     HealthCheckRequest health_check_request = 1;
110: 
111:     EndpointHealthResponse endpoint_health_response = 2;
112:   }
113: }
114: 
115: message LocalityEndpoints {
116:   api.v2.core.Locality locality = 1;
117: 
118:   repeated api.v2.endpoint.Endpoint endpoints = 2;
119: }
120: 
121: // The cluster name and locality is provided to Envoy for the endpoints that it
122: // health checks to support statistics reporting, logging and debugging by the
123: // Envoy instance (outside of HDS). For maximum usefulness, it should match the
124: // same cluster structure as that provided by EDS.
125: message ClusterHealthCheck {
126:   string cluster_name = 1;
127: 
128:   repeated api.v2.core.HealthCheck health_checks = 2;
129: 
130:   repeated LocalityEndpoints locality_endpoints = 3;
131: }
132: 
133: message HealthCheckSpecifier {
134:   repeated ClusterHealthCheck cluster_health_checks = 1;
135: 
136:   // The default is 1 second.
137:   google.protobuf.Duration interval = 2;
138: }
